solution: ```cpp
class SORTracker {
    struct Location {
        string name;
        int score;
        bool operator<(const Location& other) const {
            if (score != other.score) return score > other.score;
            return name < other.name;
        }
    };
    multiset<Location> locations;
    int queryCount = 0;
public:
    SORTracker() {}

    void add(string name, int score) {
        locations.insert({name, score});
    }

    string get() {
        auto it = locations.begin();
        advance(it, queryCount);
        ++queryCount;
        return it->name;
    }
};
```
efficiency: HIGH
time complexity: O(log N) for add, O(K) for get where K is queryCount
space complexity: O(N)
energy implications: LOW
explanation: Uses a multiset to maintain locations in sorted order by score descending then name ascending. Each add is O(log N) insertion. Each get uses advance to move the iterator to the K-th element (K = queryCount) in O(K) time. With up to 4e4 calls, worst-case K is 4e4, giving acceptable performance.

